mapper.select:
SELECT * FROM tin_tuc WHERE hoat_dong = 1
ORDER BY ngay_xuat_ban DESC, ma DESC
LIMIT #{gioiHan}

mapper.update:
UPDATE tin_tuc SET tieu_de = #{tieuDe}, tom_tat = #{tomTat}, noi_dung = #{noiDung},
    duong_anh = #{duongAnh}, ngay_xuat_ban = #{ngayXuatBan}, hoat_dong = #{hoatDong}
WHERE ma = #{ma}
